record.field:
# Create wizard
wizard = env['vendor.price.wizard'].create({
    'purchase_id': record.id,
})

# Create wizard lines from PO lines
for po_line in record.order_line.filtered(lambda l: not l.display_type):
    env['vendor.price.wizard.line'].create({
        'wizard_id': wizard.id,
        'purchase_line_id': po_line.id,
        'product_id': po_line.product_id.id,
        'product_qty': po_line.product_qty,
        'price_unit': po_line.price_unit,
        'vendor_price': po_line.price_unit,
    })

# Return action to open wizard
action = {
    'type': 'ir.actions.act_window',
    'name': 'Enter Vendor Bill Prices',
    'res_model': 'vendor.price.wizard',
    'res_id': wizard.id,
    'view_mode': 'form',
    'target': 'new',
}
